// Parse the Whapi inbound message. Emits command='' for our own messages
// (from_me) and for non-command chatter, so the IF node ignores them.
const body = $('WhatsApp Inbound').first().json.body || {};
const msg = (body.messages && body.messages[0]) || {};
const text = (msg.text && msg.text.body) ? String(msg.text.body).trim() : '';
const number = String(msg.from || '').replace(/[^0-9]/g, '');
const chatId = msg.chat_id || '';
const fromMe = msg.from_me === true;
const token = text.split(' ').filter(Boolean).find(t => t.charAt(0) === '/') || '';
const command = fromMe ? '' : token.toLowerCase();
return [{ json: { command, number, chatId, text } }];

// ── /sign-in handler. Nickname comes from the nickname_number_mapping table. ──
function normalizeNick(s){return String(s==null?'':s).trim().toLowerCase();}
function sanitizeKey(s){return String(s).replace(/[.$#\[\]\/ -]/g,'_');}
function pickLatestTid(pointer,registry){if(pointer&&typeof pointer==='string')return pointer;let best=null,bo=-Infinity;for(const [id,t] of Object.entries(registry||{})){if(!t||id.startsWith('_'))continue;const o=typeof t.order==='number'?t.order:0;if(o>bo){best=id;bo=o;}}return best;}
function matchRoster(players,nickname){const tgt=normalizeNick(nickname);return (players||[]).find(p=>normalizeNick(p)===tgt)||null;}

const cfg = $('Config').first().json;
const chatId = $('Parse Message').first().json.chatId;
const q = cfg.fbAuth || '';

// The Data Table row (empty if the number is not mapped).
const row = ($input.first() && $input.first().json) || {};
const nickname = row.nickname ? String(row.nickname) : '';

async function send(message){ if(cfg.whapiToken){ await this.helpers.httpRequest({ method:'POST', url: cfg.whapiBase+'/messages/text', headers:{ Authorization:'Bearer '+cfg.whapiToken }, body:{ to: chatId, body: message }, json:true }); } return [{ json:{ chatId, message } }]; }

if(!nickname){ return await send.call(this, '⚠️ Your number is not registered for this tournament.'); }

const pointer = await this.helpers.httpRequest({ url: cfg.fbUrl+'/latest_tournament.json'+q, json:true }).catch(()=>null);
let tid = (pointer && typeof pointer==='string') ? pointer : null;
if(!tid){ const reg = await this.helpers.httpRequest({ url: cfg.fbUrl+'/tournaments.json'+q, json:true }).catch(()=>({})); tid = pickLatestTid(null, reg||{}); }
if(!tid){ return await send.call(this, '⚠️ There is no active tournament right now.'); }

const players = await this.helpers.httpRequest({ url: cfg.fbUrl+'/tournaments/'+tid+'/players.json'+q, json:true }).catch(()=>[]);
const match = matchRoster(players, nickname);
if(!match){ return await send.call(this, '⚠️ "'+nickname+'" is not on the player list for '+tid+'.'); }

const record = { nickname: match, status:'signed_in', joined_at: Date.now(), tournament_id: tid };
await this.helpers.httpRequest({ method:'PUT', url: cfg.fbUrl+'/tournaments/'+tid+'/participants/'+sanitizeKey(match)+'.json'+q, body: record, json:true });
return await send.call(this, '✅ '+match+" — you're signed in to "+tid+'.');

// ── Default handler for any unrecognized /command. ──
const cfg = $('Config').first().json;
const chatId = $('Parse Message').first().json.chatId;
const message = 'Command not recognized.';
if(cfg.whapiToken){ await this.helpers.httpRequest({ method:'POST', url: cfg.whapiBase+'/messages/text', headers:{ Authorization:'Bearer '+cfg.whapiToken }, body:{ to: chatId, body: message }, json:true }); }
return [{ json: { chatId, message } }];
